import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BYYsWsaA.js";const g=JSON.parse('{"title":"External Datasources","description":"","frontmatter":{},"headers":[],"relativePath":"sheets/datasources.md","filePath":"sheets/datasources.md"}'),s={name:"sheets/datasources.md"};function n(l,e,i,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="external-datasources" tabindex="-1">External Datasources <a class="header-anchor" href="#external-datasources" aria-label="Permalink to &quot;External Datasources&quot;">​</a></h1><p>A <strong>datasource</strong> connects a spreadsheet to an external PostgreSQL database. You write a SQL query and its results appear in a read-only tab, right next to your regular editable sheets.</p><h2 id="connect-a-database" tabindex="-1">Connect a database <a class="header-anchor" href="#connect-a-database" aria-label="Permalink to &quot;Connect a database&quot;">​</a></h2><ol><li>Click the <strong>+</strong> at the end of the tab bar and choose <strong>New DataSource</strong>.</li><li>In the <strong>Select DataSource</strong> dialog, fill in the connection details: <ul><li><strong>Name</strong> — a label for the connection</li><li><strong>Host</strong> and <strong>Port</strong> (defaults to <code>5432</code>)</li><li><strong>Database</strong>, <strong>Username</strong>, and <strong>Password</strong></li><li><strong>SSL</strong> — toggle on if your database requires it</li></ul></li><li>Click <strong>Test Connection</strong> to confirm the credentials work, then save.</li></ol><p>A new tab is added with a database icon to distinguish it from sheet tabs.</p><h2 id="run-a-query" tabindex="-1">Run a query <a class="header-anchor" href="#run-a-query" aria-label="Permalink to &quot;Run a query&quot;">​</a></h2><p>The datasource tab has a SQL editor at the top and a results grid below it.</p><ol><li>Type a <code>SELECT</code> query — for example, <code>SELECT * FROM users LIMIT 100</code>.</li><li>Click <strong>Execute</strong>, or press <strong>⌘+Enter</strong> / <strong>Ctrl+Enter</strong>.</li></ol><p>The results load into the grid below: the first row holds the column names and each following row is a record. Re-run the query with <strong>Execute</strong> whenever you want fresh data — results don&#39;t refresh automatically.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Queries are capped at 10,000 rows and a 30-second runtime, so add a <code>LIMIT</code> clause when exploring large tables.</p></div><h2 id="working-with-results" tabindex="-1">Working with results <a class="header-anchor" href="#working-with-results" aria-label="Permalink to &quot;Working with results&quot;">​</a></h2><ul><li>The results grid is <strong>read-only</strong> — it reflects the database, so you can&#39;t edit, sort, or filter the cells in place. Shape the data with SQL instead.</li><li>Reference query results from other tabs with formulas, just like any sheet, to build summaries and dashboards on top of live data.</li></ul><h2 id="good-to-know" tabindex="-1">Good to know <a class="header-anchor" href="#good-to-know" aria-label="Permalink to &quot;Good to know&quot;">​</a></h2><ul><li>Datasources connect to <strong>PostgreSQL</strong> databases.</li><li>The connection belongs to the person who created it. Collaborators can see the query and its last results, but run their own connection to execute it.</li><li>Only the latest query for a tab is saved.</li></ul>',14)])])}const b=t(s,[["render",n]]);export{g as __pageData,b as default};
